  1	import * as React from 'react';
  2	import { InfoAltIcon } from '@patternfly/react-icons';
  3	import _round from 'lodash/round';
  4	import { HeatMap, healthColorMap } from 'components/HeatMap/HeatMap';
  5	import { MetricsStats } from 'types/Metrics';
  6	import { PFColors } from 'components/Pf/PfColors';
  7	import { Button, ButtonVariant, Tooltip } from '@patternfly/react-core';
  8	import { EnvoySpanInfo, RichSpanData } from 'types/TracingInfo';
  9	import {
 10	  compactStatsIntervals,
 11	  statsIntervals,
 12	  getSpanStats,
 13	  statsQuantilesWithAvg,
 14	  StatsMatrix,
 15	  statsToMatrix,
 16	  StatsWithIntervalIndex,
 17	  statsPerPeer,
 18	  statsCompareKind,
 19	  compactStatsQuantilesWithAvg
 20	} from 'utils/tracing/TraceStats';
 21	
 22	const statToText = {
 23	  avg: { short: 'avg', long: 'average' },
 24	  '0.5': { short: 'p50', long: 'median' },
 25	  '0.75': { short: 'p75', long: '75th percentile' },
 26	  '0.8': { short: 'p80', long: '80th percentile' },
 27	  '0.9': { short: 'p90', long: '90th percentile' },
 28	  '0.99': { short: 'p99', long: '99th percentile' },
 29	  '0.999': { short: 'p99.9', long: '99.9th percentile' }
 30	};
 31	
 32	const renderHeatMap = (item: RichSpanData, stats: StatsWithIntervalIndex[], isCompact: boolean): React.ReactNode => {
 33	  const key = `${item.spanID}-hm`;
 34	  const intervals = isCompact ? compactStatsIntervals : statsIntervals;
 35	  const quantilesWithAvg = isCompact ? compactStatsQuantilesWithAvg : statsQuantilesWithAvg;
 36	
 37	  return (
 38	    <HeatMap
 39	      key={key}
 40	      xLabels={quantilesWithAvg.map(s => statToText[s]?.short ?? s)}
 41	      yLabels={intervals}
 42	      data={statsToMatrix(stats, intervals)}
 43	      displayMode={isCompact ? 'compact' : 'normal'}
 44	      colorMap={healthColorMap}
 45	      dataRange={{ from: -10, to: 10 }}
 46	      colorUndefined={PFColors.ColorLight200}
 47	      valueFormat={v => `${v > 0 ? '+' : ''}${_round(v, 1)}`}
 48	      tooltip={(x, y, v) => {
 49	        // Build explanation tooltip
 50	        const slowOrFast = v > 0 ? 'slower' : 'faster';
 51	        const stat = statToText[quantilesWithAvg[x]]?.long || quantilesWithAvg[x];
 52	        const interval = intervals[y];
 53	        const info = item.info as EnvoySpanInfo;
 54	
 55	        let dir = 'from',
 56	          rev = 'to';
 57	
 58	        if (info.direction === 'inbound') {
 59	          dir = 'to';
 60	          rev = 'from';
 61	        }
 62	
 63	        const thisObj = statsCompareKind === 'app' ? item.app : item.workload;
 64	        const peer = statsPerPeer ? `${rev} ${info.peer}` : '';
 65	
 66	        return `This request has been ${_round(Math.abs(v), 2)}ms ${slowOrFast} than the ${stat} of all ${
 67	          info.direction
 68	        } requests ${dir} ${thisObj} ${peer} in the last ${interval}`;
 69	      }}
 70	    />
 71	  );
 72	};
 73	
 74	export const renderMetricsComparison = (
 75	  item: RichSpanData,
 76	  isCompact: boolean,
 77	  metricsStats: Map<string, MetricsStats>,
 78	  load: () => void
 79	): React.ReactNode => {
 80	  const itemStats = getSpanStats(item, metricsStats, isCompact);
 81	  const key = `${item.spanID}-metcomp`;
 82	
 83	  if (itemStats.length > 0) {
 84	    return (
 85	      <React.Fragment key={key}>
 86	        {!isCompact && (
 87	          <Tooltip
 88	            key={`${key}-tt`}
 89	            content="This heatmap is a comparison matrix of this request duration against duration statistics aggregated over time. Move the pointer over cells to get more details."
 90	          >
 91	            <>
 92	              <InfoAltIcon key={`${key}-ic`} /> <strong key={`${key}-ic-title`}>Comparison map: </strong>
 93	            </>
 94	          </Tooltip>
 95	        )}
 96	
 97	        {renderHeatMap(item, itemStats, isCompact)}
 98	      </React.Fragment>
 99	    );
100	  }
101	
102	  return (
103	    <Tooltip key={`${key}-tt`} content="Click to load more statistics for this request">
104	      <Button key={`${key}-load`} onClick={load} variant={ButtonVariant.link}>
105	        <strong key={`${key}-load-title`}>Load statistics</strong>
106	      </Button>
107	    </Tooltip>
108	  );
109	};
110	
111	export const renderTraceHeatMap = (matrix: StatsMatrix, isCompact: boolean): React.ReactNode => {
112	  const intervals = isCompact ? compactStatsIntervals : statsIntervals;
113	  const quantilesWithAvg = isCompact ? compactStatsQuantilesWithAvg : statsQuantilesWithAvg;
114	
115	  return (
116	    <HeatMap
117	      xLabels={quantilesWithAvg.map(s => statToText[s]?.short || s)}
118	      yLabels={intervals}
119	      data={matrix}
120	      displayMode={isCompact ? 'compact' : 'normal'}
121	      colorMap={healthColorMap}
122	      dataRange={{ from: -10, to: 10 }}
123	      colorUndefined={PFColors.ColorLight200}
124	      valueFormat={v => `${v > 0 ? '+' : ''}${_round(v, 1)}`}
125	      tooltip={(x, y, v) => {
126	        // Build explanation tooltip
127	        const slowOrFast = v > 0 ? 'slower' : 'faster';
128	        const stat = statToText[quantilesWithAvg[x]]?.long || quantilesWithAvg[x];
129	        const interval = intervals[y];
130	
131	        return `Trace requests have been, in average, ${_round(
132	          Math.abs(v),
133	          2
134	        )}ms ${slowOrFast} than the ${stat} of the requests involving the same services in the last ${interval}`;
135	      }}
136	    />
137	  );
138	};

